1898	
1899		src_area = find_src_area_required(local_ctm, image, clip);
1900		if (fz_is_empty_irect(src_area))
1901			return;
1902	
1903		pixmap = fz_get_pixmap_from_image(ctx, image, &src_area, &local_ctm, &dx, &dy);
1904		src_cs = fz_default_colorspace(ctx, dev->default_cs, pixmap->colorspace);
1905	
1906		/* convert images with more components (cmyk->rgb) before scaling */
1907		/* convert images with fewer components (gray->rgb) after scaling */
1908		/* convert images with expensive colorspace transforms after scaling */
1909	
1910		fz_var(pixmap);
1911	
1912		fz_try(ctx)
1913		{
1914			int conversion_required = (src_cs != model || fz_compare_separations(ctx, state->dest->seps, pixmap->seps));
