1916			if (state->blendmode & FZ_BLEND_KNOCKOUT && alpha != 1)
1917				state = fz_knockout_begin(ctx, dev);
1918	
1919			switch (fz_colorspace_type(ctx, src_cs))
1920			{
1921			case FZ_COLORSPACE_GRAY:
1922				after = 1;
1923				break;
1924			case FZ_COLORSPACE_INDEXED:
1925				after = 0;
