1928				if (fz_colorspace_n(ctx, src_cs) <= fz_colorspace_n(ctx, model))
1929					after = 1;
1930				else
1931					after = 0;
1932				break;
1933			}
1934	
1935			if (conversion_required && !after)
1936				pixmap = convert_pixmap_for_painting(ctx, pixmap, model, src_cs, state->dest, color_params, dev, &eop);
1937	
1938			if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
