1941				fz_pixmap *scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);
1942				if (!scaled)
1943				{
1944					if (dx < 1)
1945						dx = 1;
1946					if (dy < 1)
1947						dy = 1;
1948					scaled = fz_scale_pixmap_cached(ctx, pixmap, pixmap->x, pixmap->y, dx, dy, NULL, dev->cache_x, dev->cache_y);
1949				}
1950				if (scaled)
